mapper.select:
select comment.*,shopkeeper.shop_name as shopName, goods.name as goodsName,user.name as username,
user.avatar as avatar
from comment
left join  shopkeeper on shopkeeper.id=comment.shopkeeper_id
left join goods on goods.id=comment.goods_id
left join user on user.id=comment.user_id



        and comment.shopkeeper_id = #{shopkeeperId}


        and comment.goods_id = #{goodsId}


        and comment.order_no = #{orderNo}


        and shopkeeper.shop_name = #{shopName}
